const BASE_URL = 'http://192.168.1.71:3030/api/v3/backend';

// ── Token helpers ──────────────────────────────────────────────────────────────
export const auth = {
  getToken: () => localStorage.getItem('aws_token'),
  setToken: (token) => localStorage.setItem('aws_token', token),
  removeToken: () => localStorage.removeItem('aws_token'),
  isLoggedIn: () => !!localStorage.getItem('aws_token'),

  login: async (user_name, user_pass) => {
    const res = await fetch(`${BASE_URL}/users/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ user_name, user_pass }),
    });
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      throw new Error(err.message || err.detail || `Lỗi ${res.status}`);
    }
    const data = await res.json();
    // Thử các field phổ biến: access_token, token, data.token
    const token = data.access_token || data.token || data.data?.access_token || data.data?.token;
    if (!token) throw new Error('Không nhận được token từ server');
    auth.setToken(token);
    return token;
  },

  logout: () => {
    auth.removeToken();
    window.location.reload();
  },
};

// ── Fetch có Bearer token tự động ─────────────────────────────────────────────
export function authFetch(url, options = {}) {
  const token = auth.getToken();
  return fetch(url, {
    ...options,
    headers: {
      'Content-Type': 'application/json',
      ...(token ? { Authorization: `Bearer ${token}` } : {}),
      ...options.headers,
    },
  });
}
